1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	type Item = { type: string };
10	type QuoteStep = { op: "quote"; items: Array<Item> };
11	type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Array<QuoteStep>;
14	};
15	
16	const quoteStep = (step: QuoteStep): { premium: number } => {
17	  if (step.items.length === 0) {
18	    return { premium: PROCESSING_FEE };
19	  }
20	  const basePremium = step.items.reduce(
21	    (sum, item) => sum + BASE_PREMIUM[item.type],
22	    0,
23	  );
24	  const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
25	  return { premium: Math.ceil(premium - 1e-9) };
26	};
27	
28	export const processScenario = (scenario: unknown): unknown => {
29	  const { steps } = scenario as Scenario;
30	  return { results: steps.map(quoteStep) };
31	};
